import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import axios from 'axios';
import Navbar from "./components/Navbar";

const cacheBusqueda = {};

function App() {
  // --- ESTADOS ---
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [authMode, setAuthMode] = useState('login'); 
  const [usuario, setUsuario] = useState('');
  const [password, setPassword] = useState('');
  const [email, setEmail] = useState(''); 
  const [telefono, setTelefono] = useState(''); 
  const [userRole, setUserRole] = useState('vendedor');
  const [nuevoRol, setNuevoRol] = useState('vendedor');
  const [fotoArchivo, setFotoArchivo] = useState(null); 

  const [view, setView] = useState('dashboard');
  const [filtroBajoStock, setFiltroBajoStock] = useState(false); 
  const [stats, setStats] = useState({ total_productos: 0, valor_inventario: 0, bajo_stock: 0 });
  const [productos, setProductos] = useState([]);
  const [busqueda, setBusqueda] = useState('');
  const [loading, setLoading] = useState(false);

  const [showForm, setShowForm] = useState(false);
  const [nuevoProd, setNuevoProd] = useState({ nombre: '', stock: '', precio_venta: '' });

  const [twoStep, setTwoStep] = useState(false); 
  const [otp, setOtp] = useState(''); 

  const abortControllerRef = useRef(null);

  // 1. CARGA DE DATOS
  const cargarDatos = useCallback(async () => {
    if (busqueda.length > 0) return; 
    setLoading(true);
    try {
      const [resStats, resProds] = await Promise.all([
        axios.get('http://localhost:5000/api/stats'),
        axios.get('http://localhost:5000/api/productos')
      ]);
      setStats(resStats.data);
      setProductos(resProds.data);
    } catch (error) { console.error(error); } 
    finally { setLoading(false); }
  }, [busqueda]);

  useEffect(() => {
    if (isLoggedIn) {
      cargarDatos();
      const interval = setInterval(cargarDatos, 30000);
      return () => clearInterval(interval);
    }
  }, [isLoggedIn, cargarDatos]);

  // 2. BUSQUEDA DINÁMICA
  const ejecutarBusqueda = useCallback(async (texto) => {
    if (texto.trim() === '') { cargarDatos(); return; }
    if (cacheBusqueda[texto]) { setProductos(cacheBusqueda[texto]); return; }
    if (abortControllerRef.current) abortControllerRef.current.abort();
    abortControllerRef.current = new AbortController();
    try {
      const res = await axios.get(`http://localhost:5000/api/productos/buscar?q=${texto}`, { 
        signal: abortControllerRef.current.signal 
      });
      cacheBusqueda[texto] = res.data;
      setProductos(res.data);
    } catch (err) { if (err.name !== 'CanceledError') console.error(err); }
  }, [cargarDatos]);

  const optimizadaBusqueda = useMemo(() => {
    const debounce = (fn, delay) => {
      let timeout;
      return (...args) => { clearTimeout(timeout); timeout = setTimeout(() => fn(...args), delay); };
    };
    return debounce(ejecutarBusqueda, 300);
  }, [ejecutarBusqueda]);

  const handleBusquedaChange = (e) => {
    setBusqueda(e.target.value);
    optimizadaBusqueda(e.target.value);
  };

  // --- LÓGICA DE ACCESO ---
  const handleLogin = async () => {
    try {
      const res = await axios.post('http://localhost:5000/api/login', { usuario, clave: password });
      if (res.data.success) {
        setEmail(res.data.email);
        setTwoStep(true); 
      }
    } catch (e) { alert("Usuario o clave incorrectos"); }
  };

  const verificarOTP = async () => {
    try {
      const res = await axios.post('http://localhost:5000/api/verify-otp', { usuario, otp });
      if (res.data.success) {
        setUserRole(res.data.rol);
        setIsLoggedIn(true);
      } else { alert("Código incorrecto"); }
    } catch (e) { alert("Error"); }
  };

  const handleRegister = async () => {
    if (!usuario || !password || !email || !telefono) return alert("Faltan datos");
    try {
      await axios.post('http://localhost:5000/api/register', { email, usuario, telefono, clave: password, rol: nuevoRol });
      alert("¡Registro exitoso!");
      setAuthMode('login');
    } catch (e) { alert("Error al registrar"); }
  };

  const manejarRecuperacion = async () => {
    try {
        const res = await axios.post('http://localhost:5000/api/recover', { email });
        alert(res.data.message);
        setAuthMode('login');
    } catch (e) { alert("Email no encontrado"); }
  };

  const handleLogout = () => {
    setIsLoggedIn(false);
    setTwoStep(false); // <--- FIX: Resetea la verificación
    setAuthMode('login'); // <--- FIX: Manda al login limpio
  };

  // --- LÓGICA DE PRODUCTOS ---
  const guardarProducto = async () => {
    const formData = new FormData();
    formData.append('nombre', nuevoProd.nombre);
    formData.append('stock', nuevoProd.stock);
    formData.append('precio_venta', nuevoProd.precio_venta);
    if (fotoArchivo) formData.append('imagen', fotoArchivo);

    try {
      await axios.post('http://localhost:5000/api/productos', formData, {
        headers: { 'Content-Type': 'multipart/form-data' }
      });
      setShowForm(false);
      cargarDatos();
      setNuevoProd({ nombre: '', stock: '', precio_venta: '' });
      setFotoArchivo(null);
      alert("Guardado");
    } catch (e) { alert("Error"); }
  };

  const eliminar = async (id) => {
    if (window.confirm("¿Eliminar?")) {
      await axios.delete(`http://localhost:5000/api/productos/${id}`);
      cargarDatos();
    }
  };

  if (!isLoggedIn) {
    return (
      <div className="min-h-screen bg-[#bdc3c7] flex items-center justify-center p-4 font-sans">
        <div className="bg-[#2d333b] p-10 rounded-[40px] shadow-2xl w-full max-w-sm border border-gray-700 text-white text-center">

          {twoStep ? (
            <div className="animate-in zoom-in duration-300">
              <i className="fas fa-shield-halved text-[#00c984] text-5xl mb-6"></i>
              <h2 className="text-2xl font-black mb-2 uppercase">Verificación</h2>
              <p className="text-gray-400 text-[10px] mb-8 uppercase tracking-widest leading-none">Código enviado a:<br/>{email}</p>
              <input maxLength="6" placeholder="000000" className="w-full bg-[#444c56] text-white text-center text-5xl font-black py-5 rounded-[30px] outline-none mb-8 tracking-[10px]" onChange={e => setOtp(e.target.value)} />
              <button className="w-full bg-[#00c984] text-[#1e293b] font-black py-5 rounded-[30px] text-xl uppercase transition active:scale-95" onClick={verificarOTP}>Entrar</button>
              <p className="text-[10px] text-gray-500 mt-4 cursor-pointer uppercase font-black" onClick={() => setTwoStep(false)}>Volver</p>
            </div>
          ) : (
            <div className="space-y-4">
              <h2 className="text-3xl font-black uppercase tracking-tighter mb-6">Mi Tiendita Pro</h2>

              {authMode !== 'recovery' && (
                  <input className="w-full bg-[#444c56] text-white px-6 py-4 rounded-3xl outline-none" placeholder="Usuario" onChange={e => setUsuario(e.target.value)} />
              )}

              {authMode === 'register' && (
                <>
                  <input className="w-full bg-[#444c56] text-white px-6 py-4 rounded-3xl outline-none" placeholder="Email" onChange={e => setEmail(e.target.value)} />
                  <input className="w-full bg-[#444c56] text-white px-6 py-4 rounded-3xl outline-none" placeholder="Teléfono" onChange={e => setTelefono(e.target.value)} />
                  <select className="w-full bg-[#444c56] text-white px-6 py-4 rounded-3xl outline-none" value={nuevoRol} onChange={e => setNuevoRol(e.target.value)}>
                    <option value="vendedor">Vendedor</option>
                    <option value="admin">Administrador</option>
                  </select>
                </>
              )}

              {authMode === 'recovery' && (
                  <>
                  <p className="text-xs text-gray-400 mb-2 uppercase font-black">Recuperar por Email</p>
                  <input className="w-full bg-[#444c56] text-white px-6 py-4 rounded-3xl outline-none border border-[#00c984]" placeholder="Tu Email" onChange={e => setEmail(e.target.value)} />
                  </>
              )}

              {authMode !== 'recovery' && (
                <input type="password" title="Contraseña" className="w-full bg-[#444c56] text-white px-6 py-4 rounded-3xl outline-none" placeholder="Contraseña" onChange={e => setPassword(e.target.value)} />
              )}

              <button className="w-full bg-[#00c984] text-[#1e293b] font-black py-5 rounded-[30px] shadow-lg text-lg uppercase transition active:scale-95" 
                onClick={authMode === 'login' ? handleLogin : authMode === 'recovery' ? manejarRecuperacion : handleRegister}>
                {authMode}
              </button>

              <div className="flex justify-between text-[10px] text-gray-400 font-bold uppercase cursor-pointer pt-4 px-2">
                <span className="hover:text-[#00c984]" onClick={() => setAuthMode(authMode === 'login' ? 'register' : 'login')}>
                  {authMode === 'login' ? 'Registro' : 'Login'}
                </span>
                <span className="hover:text-[#00c984]" onClick={() => setAuthMode('recovery')}>¿Olvidaste clave?</span>
              </div>
            </div>
          )}
        </div>
      </div>
    );
  }

  const prodFiltrados = productos.filter(p => 
    p.nombre.toLowerCase().includes(busqueda.toLowerCase())
  );

  return (
    <div className="min-h-screen bg-gray-50 text-slate-800">
      <Navbar setView={setView} userRole={userRole} logout={handleLogout} busqueda={busqueda} handleBusquedaChange={handleBusquedaChange} />

      <main className="max-w-7xl mx-auto p-4 md:p-12">
        {busqueda.length > 0 ? (
          <div className="space-y-6 animate-in fade-in duration-300">
            <h2 className="text-3xl font-black uppercase tracking-tighter italic text-[#1e293b]">Buscando: "{busqueda}"</h2>
            <div className="grid grid-cols-1 md:grid-cols-4 gap-6 text-center">
                {prodFiltrados.map(p => (
                    <div key={p.id} className="bg-white p-6 rounded-[40px] shadow-xl border border-gray-100">
                      <img src={p.imagen ? `http://localhost:5000/uploads/${p.imagen}` : 'https://via.placeholder.com/150'} className="w-full h-40 object-cover rounded-3xl mb-4" alt="p" />
                      <h3 className="font-black uppercase text-sm mb-1">{p.nombre}</h3>
                      <p className="text-green-600 font-black text-2xl mb-2">${p.precio_venta}</p>
                      {/* SOLO ADMIN PUEDE BORRAR AQUÍ */}
                      {userRole === 'admin' && (
                        <button onClick={() => eliminar(p.id)} className="text-red-400 mt-2"><i className="fas fa-trash"></i></button>
                      )}
                    </div>
                ))}
            </div>
          </div>
        ) : (
          <>
            {view === "dashboard" ? (
              <div className="space-y-10 animate-in slide-in-from-bottom-4 duration-500">
                <h2 className="text-3xl font-black uppercase italic tracking-tighter text-[#1e293b]">Resumen del Almacén</h2>
                <div className="grid grid-cols-1 md:grid-cols-3 gap-8 text-center">
                  <div onClick={() => { setView('productos'); setFiltroBajoStock(false); }} className="bg-white p-10 border-2 rounded-[50px] shadow-xl cursor-pointer hover:scale-105 transition border-slate-50">
                    <p className="text-xs text-slate-400 font-black uppercase mb-2 tracking-widest italic tracking-widest">Stock Total</p>
                    <p className="text-6xl font-black text-[#1e293b]">{stats.total_productos}</p>
                  </div>
                  <div onClick={() => { setView('productos'); setFiltroBajoStock(true); }} className="bg-white p-10 border-2 rounded-[50px] shadow-xl cursor-pointer hover:scale-105 transition border-slate-50">
                    <p className="text-xs text-red-400 font-black uppercase mb-2 tracking-widest italic tracking-widest">Bajo Almacén</p>
                    <p className="text-6xl font-black text-red-500">{stats.bajo_stock}</p>
                  </div>
                  <div className="bg-white p-10 border-2 rounded-[50px] shadow-xl border-slate-50">
                    <p className="text-xs text-green-400 font-black uppercase mb-2 tracking-widest italic tracking-widest">Capital Invertido</p>
                    <p className="text-5xl font-black text-green-600">${stats.valor_inventario.toLocaleString()}</p>
                  </div>
                </div>
              </div>
            ) : (
              <div className="space-y-6 animate-in fade-in duration-300">
                <div className="flex justify-between items-center">
                  <h2 className="text-3xl font-black uppercase tracking-tighter text-[#1e293b]">
                    {filtroBajoStock ? "📦 Faltantes" : "📦 Todo el Almacén"}
                  </h2>

                  {/* SOLO ADMIN PUEDE VER EL BOTÓN AGREGAR */}
                  {userRole === 'admin' && (
                    <button onClick={() => setShowForm(!showForm)} className="bg-[#1e293b] text-white px-10 py-4 rounded-3xl font-black text-sm uppercase shadow-xl hover:scale-105 transition">
                        {showForm ? 'Cerrar Panel' : '+ Agregar Producto'}
                    </button>
                  )}
                </div>

                {showForm && userRole === 'admin' && (
                  <div className="bg-white p-8 rounded-[40px] border-4 border-dashed grid grid-cols-1 md:grid-cols-5 gap-4 shadow-inner text-center">
                    <input className="p-4 bg-gray-50 rounded-2xl outline-none font-bold" placeholder="Nombre" value={nuevoProd.nombre} onChange={e => setNuevoProd({...nuevoProd, nombre: e.target.value})} />
                    <input className="p-4 bg-gray-50 rounded-2xl outline-none font-bold" placeholder="Stock" type="number" value={nuevoProd.stock} onChange={e => setNuevoProd({...nuevoProd, stock: e.target.value})} />
                    <input className="p-4 bg-gray-50 rounded-2xl outline-none font-bold" placeholder="Precio" type="number" value={nuevoProd.precio_venta} onChange={e => setNuevoProd({...nuevoProd, precio_venta: e.target.value})} />
                    <input type="file" className="text-[10px] mt-4" onChange={e => setFotoArchivo(e.target.files[0])} />
                    <button onClick={guardarProducto} className="bg-[#00c984] text-[#1e293b] font-black rounded-2xl py-4 uppercase shadow-lg">Guardar</button>
                  </div>
                )}

                <div className="bg-white border rounded-[40px] shadow-2xl overflow-hidden overflow-x-auto">
                  <table className="w-full text-left">
                    <thead className="bg-gray-100 text-[10px] font-black uppercase text-gray-400 tracking-widest text-center">
                      <tr><th className="p-8">Foto</th><th className="p-8">Descripción</th><th className="p-8">Stock</th><th className="p-8">Costo</th><th className="p-8">Acciones</th></tr>
                    </thead>
                    <tbody className="divide-y text-sm font-bold text-slate-700 text-center">
                      {productos.filter(p => filtroBajoStock ? p.stock < 10 : true).map(p => (
                        <tr key={p.id} className="hover:bg-slate-50 transition">
                          <td className="p-8 flex justify-center">
                             <img src={p.imagen ? `http://localhost:5000/uploads/${p.imagen}` : 'https://via.placeholder.com/50'} className="w-16 h-16 object-cover rounded-2xl shadow-sm" alt="img" />
                          </td>
                          <td className="p-8 uppercase font-black text-[#1e293b] text-lg">{p.nombre}</td>
                          <td className="p-8">
                            <span className={`px-5 py-2 rounded-full text-[10px] font-black border-2 ${p.stock < 10 ? 'bg-red-50 text-red-600 border-red-100' : 'bg-green-50 text-green-600 border-green-100'}`}>{p.stock} UNID.</span>
                          </td>
                          <td className="p-8 text-2xl font-black text-slate-800">${p.precio_venta}</td>
                          <td className="p-8">
                            {/* SOLO ADMIN PUEDE BORRAR EN LA TABLA */}
                            {userRole === 'admin' ? (
                                <button onClick={() => eliminar(p.id)} className="p-4 bg-red-50 text-red-400 rounded-2xl hover:bg-red-500 hover:text-white transition"><i className="fas fa-trash-alt"></i></button>
                            ) : (
                                <span className="text-[10px] text-gray-300 uppercase">Sin Permiso</span>
                            )}
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>
            )}
          </>
        )}
      </main>
    </div>
  );
}

export default App;
